+import { describe, it, expect, beforeEach } from 'vitest';
+import { Database } from '../../src/utils/database.js';
+import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
+import type { UserPreferences } from '../../src/models/user-preferences.js';
+
+describe('PreferencesRepository', () => {
+  let db: Database;
+  let repo: PreferencesRepository;
+
+  const makePrefs = (overrides?: Partial<UserPreferences>): UserPreferences => ({
+    id: 'pref-0001',
+    userId: 'user-1',
+    email: {
+      enabled: true,
+      frequency: 'immediate',
+      subscribedCategories: ['order_confirmation', 'order_status_update'],
+    },
+    createdAt: new Date('2026-01-01'),
+    updatedAt: new Date('2026-01-01'),
+    ...overrides,
+  });
+
+  beforeEach(() => {
+    db = new Database();
+    repo = new PreferencesRepository(db);
+  });
+
+  it('should save and retrieve preferences', () => {
+    const prefs = makePrefs();
+    repo.save(prefs);
+
+    const found = repo.findById('pref-0001');
+    expect(found).toBeDefined();
+    expect(found!.userId).toBe('user-1');
+    expect(found!.email.enabled).toBe(true);
+    expect(found!.email.frequency).toBe('immediate');
+    expect(found!.email.subscribedCategories).toEqual([
+      'order_confirmation',
+      'order_status_update',
+    ]);
+  });
+
+  it('should find preferences by userId', () => {
+    repo.save(makePrefs({ id: 'pref-0001', userId: 'user-1' }));
+    repo.save(makePrefs({ id: 'pref-0002', userId: 'user-2' }));
+
+    const found = repo.findByUserId('user-1');
+    expect(found).toBeDefined();
+    expect(found!.userId).toBe('user-1');
+
+    const notFound = repo.findByUserId('user-999');
+    expect(notFound).toBeUndefined();
+  });
+
+  it('should round-trip date serialization', () => {
+    const prefs = makePrefs({ createdAt: new Date('2026-03-15T10:30:00Z') });
+    repo.save(prefs);
+
+    const found = repo.findById('pref-0001');
+    expect(found!.createdAt).toEqual(new Date('2026-03-15T10:30:00Z'));
+  });
+
+  it('should round-trip subscribedCategories through JSON serialization', () => {
+    const prefs = makePrefs({
+      email: {
+        enabled: true,
+        frequency: 'weekly',
+        subscribedCategories: ['user_welcome'],
+      },
+    });
+    repo.save(prefs);
+
+    const found = repo.findById('pref-0001');
+    expect(found!.email.subscribedCategories).toEqual(['user_welcome']);
+    expect(found!.email.frequency).toBe('weekly');
+  });
+});

