/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications via email.
 * Currently email is the only channel; the model is designed to
 * accommodate additional channels in the future.
 */

import type { NotificationType } from './notification.js';

/**
 * How often email notifications are batched and sent.
 * - 'immediate': each notification is sent as it occurs
 * - 'daily': notifications are batched into a daily digest
 * - 'weekly': notifications are batched into a weekly digest
 */
export type EmailFrequency = 'immediate' | 'daily' | 'weekly';

/**
 * Email-specific notification settings.
 */
export interface EmailPreferences {
  enabled: boolean;
  frequency: EmailFrequency;
  subscribedCategories: NotificationType[];
}

/**
 * Full notification preferences for a user.
 */
export interface UserPreferences {
  id: string;
  userId: string;
  email: EmailPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for creating user preferences (userId is set separately).
 */
export interface CreatePreferencesInput {
  email?: Partial<EmailPreferences>;
}

/**
 * Input for updating existing user preferences.
 */
export interface UpdatePreferencesInput {
  email?: Partial<EmailPreferences>;
}

/**
 * All notification types that are subscribable by default.
 */
export const ALL_NOTIFICATION_CATEGORIES: NotificationType[] = [
  'order_confirmation',
  'order_status_update',
  'user_welcome',
  'user_updated',
];

/**
 * Default email preferences for new users.
 */
export const DEFAULT_EMAIL_PREFERENCES: EmailPreferences = {
  enabled: true,
  frequency: 'immediate',
  subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
};

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preference-specific query methods.
 * Depends on the Database utility layer for storage.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserPreferences } from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import type { EmailFrequency } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: {
        enabled: record['emailEnabled'] as boolean,
        frequency: record['emailFrequency'] as EmailFrequency,
        subscribedCategories: JSON.parse(
          record['emailSubscribedCategories'] as string,
        ) as NotificationType[],
      },
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      emailEnabled: entity.email.enabled,
      emailFrequency: entity.email.frequency,
      emailSubscribedCategories: JSON.stringify(entity.email.subscribedCategories),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences by user ID.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD operations for user notification preferences and
 * exposes query methods used by the NotificationService to decide
 * whether a notification should be sent.
 *
 * Depends on:
 *   - PreferencesRepository for data access
 */

import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type {
  UserPreferences,
  CreatePreferencesInput,
  UpdatePreferencesInput,
} from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import {
  DEFAULT_EMAIL_PREFERENCES,
  ALL_NOTIFICATION_CATEGORIES,
} from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private preferencesRepo: PreferencesRepository) {}

  /**
   * Create default preferences for a user. If preferences already exist,
   * returns the existing preferences.
   */
  createPreferences(userId: string, input?: CreatePreferencesInput): UserPreferences {
    const existing = this.preferencesRepo.findByUserId(userId);
    if (existing) {
      this.logger.info(`Preferences already exist for user ${userId}`);
      return existing;
    }

    const emailInput = input?.email ?? {};
    const preferences: UserPreferences = {
      id: generatePreferencesId(),
      userId,
      email: {
        enabled: emailInput.enabled ?? DEFAULT_EMAIL_PREFERENCES.enabled,
        frequency: emailInput.frequency ?? DEFAULT_EMAIL_PREFERENCES.frequency,
        subscribedCategories:
          emailInput.subscribedCategories ?? [...DEFAULT_EMAIL_PREFERENCES.subscribedCategories],
      },
      createdAt: new Date(),
      updatedAt: new Date(),
    };

    this.preferencesRepo.save(preferences);
    this.logger.info(`Created preferences ${preferences.id} for user ${userId}`);
    return preferences;
  }

  /**
   * Get preferences for a user. Returns undefined if none exist.
   */
  getPreferences(userId: string): UserPreferences | undefined {
    return this.preferencesRepo.findByUserId(userId);
  }

  /**
   * Update a user's notification preferences.
   */
  updatePreferences(userId: string, input: UpdatePreferencesInput): UserPreferences {
    const existing = this.preferencesRepo.findByUserId(userId);
    if (!existing) {
      throw new Error(`Preferences not found for user: ${userId}`);
    }

    const emailInput = input.email ?? {};
    const updated: UserPreferences = {
      ...existing,
      email: {
        enabled: emailInput.enabled ?? existing.email.enabled,
        frequency: emailInput.frequency ?? existing.email.frequency,
        subscribedCategories:
          emailInput.subscribedCategories ?? existing.email.subscribedCategories,
      },
      updatedAt: new Date(),
    };

    this.preferencesRepo.update(existing.id, updated);
    this.logger.info(`Updated preferences for user ${userId}`);
    return updated;
  }

  /**
   * Check whether email notifications are allowed for a user and notification type.
   * If no preferences exist, notifications are allowed by default (opt-out model).
   */
  isEmailAllowed(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.preferencesRepo.findByUserId(userId);
    if (!prefs) {
      return true;
    }
    if (!prefs.email.enabled) {
      return false;
    }
    return prefs.email.subscribedCategories.includes(notificationType);
  }

  /**
   * Validate that the given categories are all valid notification types.
   */
  validateCategories(categories: string[]): categories is NotificationType[] {
    return categories.every((cat) =>
      (ALL_NOTIFICATION_CATEGORIES as string[]).includes(cat),
    );
  }
}

