import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { ALL_NOTIFICATION_CATEGORIES } from '../../src/models/user-preferences.js';

describe('PreferencesService', () => {
  let db: Database;
  let repo: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    repo = new PreferencesRepository(db);
    service = new PreferencesService(repo);
    resetPreferencesIdCounter();
  });

  describe('createPreferences', () => {
    it('should create default preferences for a user', () => {
      const prefs = service.createPreferences('user-1');

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should create preferences with custom email settings', () => {
      const prefs = service.createPreferences('user-1', {
        email: {
          enabled: true,
          frequency: 'daily',
          subscribedCategories: ['order_confirmation'],
        },
      });

      expect(prefs.email.frequency).toBe('daily');
      expect(prefs.email.subscribedCategories).toEqual(['order_confirmation']);
    });

    it('should return existing preferences if already created', () => {
      const first = service.createPreferences('user-1');
      const second = service.createPreferences('user-1', {
        email: { frequency: 'weekly' },
      });

      expect(second.id).toBe(first.id);
      expect(second.email.frequency).toBe('immediate');
    });

    it('should generate sequential IDs', () => {
      const p1 = service.createPreferences('user-1');
      const p2 = service.createPreferences('user-2');

      expect(p1.id).toBe('pref-0001');
      expect(p2.id).toBe('pref-0002');
    });

    it('should allow partial email overrides with defaults for the rest', () => {
      const prefs = service.createPreferences('user-1', {
        email: { frequency: 'weekly' },
      });

      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('weekly');
      expect(prefs.email.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });
  });

  describe('getPreferences', () => {
    it('should return preferences for an existing user', () => {
      service.createPreferences('user-1');
      const prefs = service.getPreferences('user-1');

      expect(prefs).toBeDefined();
      expect(prefs!.userId).toBe('user-1');
    });

    it('should return undefined for a user with no preferences', () => {
      const prefs = service.getPreferences('user-999');
      expect(prefs).toBeUndefined();
    });
  });

  describe('updatePreferences', () => {
    it('should update email enabled flag', () => {
      service.createPreferences('user-1');
      const updated = service.updatePreferences('user-1', {
        email: { enabled: false },
      });

      expect(updated.email.enabled).toBe(false);
      expect(updated.email.frequency).toBe('immediate');
      expect(updated.email.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should update email frequency', () => {
      service.createPreferences('user-1');
      const updated = service.updatePreferences('user-1', {
        email: { frequency: 'daily' },
      });

      expect(updated.email.frequency).toBe('daily');
    });

    it('should update subscribed categories', () => {
      service.createPreferences('user-1');
      const updated = service.updatePreferences('user-1', {
        email: { subscribedCategories: ['order_confirmation', 'order_status_update'] },
      });

      expect(updated.email.subscribedCategories).toEqual([
        'order_confirmation',
        'order_status_update',
      ]);
    });

    it('should throw when updating preferences for unknown user', () => {
      expect(() =>
        service.updatePreferences('user-999', { email: { enabled: false } }),
      ).toThrow('Preferences not found for user: user-999');
    });

    it('should persist updates across reads', () => {
      service.createPreferences('user-1');
      service.updatePreferences('user-1', { email: { enabled: false } });

      const prefs = service.getPreferences('user-1');
      expect(prefs!.email.enabled).toBe(false);
    });
  });

  describe('isEmailAllowed', () => {
    it('should allow email when no preferences exist (opt-out model)', () => {
      expect(service.isEmailAllowed('user-999', 'order_confirmation')).toBe(true);
    });

    it('should allow email when preferences have email enabled and category subscribed', () => {
      service.createPreferences('user-1');
      expect(service.isEmailAllowed('user-1', 'order_confirmation')).toBe(true);
    });

    it('should block email when email is disabled', () => {
      service.createPreferences('user-1');
      service.updatePreferences('user-1', { email: { enabled: false } });

      expect(service.isEmailAllowed('user-1', 'order_confirmation')).toBe(false);
    });

    it('should block email when category is not subscribed', () => {
      service.createPreferences('user-1', {
        email: { subscribedCategories: ['order_confirmation'] },
      });

      expect(service.isEmailAllowed('user-1', 'order_confirmation')).toBe(true);
      expect(service.isEmailAllowed('user-1', 'order_status_update')).toBe(false);
    });

    it('should block all categories when email is disabled even if categories are set', () => {
      service.createPreferences('user-1', {
        email: { enabled: false, subscribedCategories: ALL_NOTIFICATION_CATEGORIES },
      });

      expect(service.isEmailAllowed('user-1', 'order_confirmation')).toBe(false);
    });
  });

  describe('validateCategories', () => {
    it('should accept valid categories', () => {
      expect(service.validateCategories(['order_confirmation', 'user_welcome'])).toBe(true);
    });

    it('should reject invalid categories', () => {
      expect(service.validateCategories(['order_confirmation', 'invalid_type'])).toBe(false);
    });

    it('should accept empty array', () => {
      expect(service.validateCategories([])).toBe(true);
    });
  });
});

